bodyStatements.text:
for i: int := 0 to |s|
  invariant z == CountChar(s[..i], 'z')
  invariant e == CountChar(s[..i], 'e')
  invariant r == CountChar(s[..i], 'r')
  invariant o == CountChar(s[..i], 'o')
  invariant n == CountChar(s[..i], 'n')
{
  CountCharStep(s, i, 'z');
  CountCharStep(s, i, 'e');
  CountCharStep(s, i, 'r');
  CountCharStep(s, i, 'o');
  CountCharStep(s, i, 'n');
  if s[i] == 'z' {
    z := z + 1;
  } else if s[i] == 'e' {
    e := e + 1;
  } else if s[i] == 'r' {
    r := r + 1;
  } else if s[i] == 'o' {
    o := o + 1;
  } else {
    assert s[i] == 'n';
    n := n + 1;
  }
}
